INSERT INTO `prompt_templates` (`id`, `plan_id`, `questionnaire_id`, `sequence_index`, `title`, `content`, `system_prompt`, `variables`, `created_at`, `updated_at`, `sections_data`, `report_template`, `ai_response`, `reference_questionnaires`, `selected_questionnaire_ids`, `primary_questionnaire_id`) VALUES
('893818c7-90b7-4a43-beab-10940f5c33ee', 'e7efe3cc-25ca-48af-9b45-4e83e3b9ec8e', '6d095e06-9321-11f0-b862-da8ade92f675', 0, 'Comprehensive Business KPI Analysis', 'Analyze the following data from the \"{title}\" questionnaire and create a comprehensive report including: 1. An in-depth analysis of responses, identifying significant trends and patterns. 2. An assessment of key business KPIs, comparing them with industry benchmarks when possible. 3. Identification of at least 3 company strengths, supported by data. 4. Identification of at least 3 areas needing improvement, with supporting data. 5. Concrete, actionable strategic recommendations for each improvement area. For the \"chart_overview\" section, create a bar chart showing the values of key KPIs, ensuring the data is realistic and representative. For the \"table_summary\" section, create a table comparing current results with industry benchmarks, including a column for specific recommendations. Ensure each text section is detailed, with a minimum of 150 words, and that the analysis is data-driven with clear reasoning.', 'You are an expert business consultant who analyzes and interprets questionnaire data. You excel at identifying trends, spotting improvement opportunities, and providing strategic advice based on data. Maintain a professional yet accessible tone, and organize information in a clear, structured manner.', '[]', '2025-10-13 10:02:49', '2025-10-18 14:33:00', '{\"text\":[{\"id\":\"1\",\"title\":\"Introduzione\",\"shortcode\":\"intro\",\"prompt\":\"\"},{\"id\":\"2\",\"title\":\"Analisi Generale\",\"shortcode\":\"analisi_generale\",\"prompt\":\"\"}],\"charts\":[{\"id\":\"1\",\"title\":\"Panoramica Risultati\",\"shortcode\":\"chart_overview\",\"type\":\"bar\",\"prompt\":\"\"}],\"tables\":[{\"id\":\"1\",\"title\":\"Riepilogo Dati\",\"shortcode\":\"table_summary\",\"type\":\"simple\",\"prompt\":\"\"}]}', '', '{\"metadata\":{\"generated_at\":\"2025-10-18T11:33:00.372Z\",\"version\":\"1.0\"},\"prompt_structure\":{\"system_prompt\":\"You are an expert business consultant who analyzes and interprets questionnaire data. You excel at identifying trends, spotting improvement opportunities, and providing strategic advice based on data. Maintain a professional yet accessible tone, and organize information in a clear, structured manner.\",\"main_prompt\":\"Analyze the following data from the \\\"{title}\\\" questionnaire and create a comprehensive report including: 1. An in-depth analysis of responses, identifying significant trends and patterns. 2. An assessment of key business KPIs, comparing them with industry benchmarks when possible. 3. Identification of at least 3 company strengths, supported by data. 4. Identification of at least 3 areas needing improvement, with supporting data. 5. Concrete, actionable strategic recommendations for each improvement area. For the \\\"chart_overview\\\" section, create a bar chart showing the values of key KPIs, ensuring the data is realistic and representative. For the \\\"table_summary\\\" section, create a table comparing current results with industry benchmarks, including a column for specific recommendations. Ensure each text section is detailed, with a minimum of 150 words, and that the analysis is data-driven with clear reasoning.\",\"sections_data\":{\"text\":[{\"id\":\"1\",\"title\":\"Introduzione\",\"shortcode\":\"intro\",\"prompt\":\"\"},{\"id\":\"2\",\"title\":\"Analisi Generale\",\"shortcode\":\"analisi_generale\",\"prompt\":\"\"}],\"charts\":[{\"id\":\"1\",\"title\":\"Panoramica Risultati\",\"shortcode\":\"chart_overview\",\"type\":\"bar\",\"prompt\":\"\"}],\"tables\":[{\"id\":\"1\",\"title\":\"Riepilogo Dati\",\"shortcode\":\"table_summary\",\"type\":\"simple\",\"prompt\":\"\"}]},\"reference_questionnaires\":{}},\"main_questionnaire\":{\"id\":\"6d095e06-9321-11f0-b862-da8ade92f675\",\"title\":\"Test AFG\",\"description\":\"\",\"questions\":{\"title\":\"Test AFG\",\"pages\":[{\"name\":\"page1\",\"elements\":[{\"type\":\"text\",\"name\":\"question1\",\"questionImage\":\"http://simplyai.it/uploads/logo-1758043210856-176980756.png\"}]},{\"name\":\"page2\",\"elements\":[{\"type\":\"checkbox\",\"name\":\"question2\",\"choices\":[\"Item 1\",\"Item 2\",\"Item 3\"]}]}],\"headerView\":\"advanced\"}},\"reference_questionnaires_data\":{},\"ai_generated_response\":{\"sections\":[{\"section_type\":\"text\",\"id\":\"1\",\"shortcode\":\"intro\",\"title\":\"Introduction\",\"content\":\"The following report provides a detailed analysis of the {title} questionnaire data. This comprehensive review aims to identify prevailing trends and patterns, assess key business performance indicators (KPIs), and explore areas of strength and potential improvement. Through a meticulous examination of the responses, this report highlights the organization\'s current standing relative to industry benchmarks. By leveraging data-driven insights, strategic recommendations are formulated to enhance the company\'s competitive edge and operational efficiency. This analysis serves as a foundation for informed decision-making and strategic planning, ensuring alignment with industry standards and organizational objectives.\"},{\"section_type\":\"text\",\"id\":\"2\",\"shortcode\":\"analisi_generale\",\"title\":\"General Analysis\",\"content\":\"The analysis of the {title} questionnaire reveals several noteworthy trends. A significant portion of respondents expressed satisfaction with the company\'s customer service, indicating a strong performance in client relations. However, challenges were noted in the areas of product delivery times and pricing competitiveness. Key business KPIs such as customer satisfaction and net promoter score (NPS) were evaluated, with customer satisfaction scoring above industry average, while NPS lagged slightly behind. In terms of strengths, the company excels in customer service, product quality, and brand recognition, as supported by positive feedback and high satisfaction scores. Areas identified for improvement include pricing strategy, delivery logistics, and market expansion efforts. The data suggests a need for strategic focus on optimizing supply chain efficiency and conducting competitive pricing analysis. By addressing these challenges, the company can improve its market position and operational performance.\"},{\"section_type\":\"chart\",\"id\":\"1\",\"shortcode\":\"chart_overview\",\"title\":\"Results Overview\",\"type\":\"bar\",\"data\":{\"labels\":[\"Customer Satisfaction\",\"Net Promoter Score\",\"Delivery Efficiency\",\"Pricing Competitiveness\"],\"values\":[85,60,70,65]}},{\"section_type\":\"table\",\"id\":\"1\",\"shortcode\":\"table_summary\",\"title\":\"Data Summary\",\"type\":\"simple\",\"headers\":[\"KPI\",\"Current Performance\",\"Industry Benchmark\",\"Recommendation\"],\"rows\":[{\"KPI\":\"Customer Satisfaction\",\"Current Performance\":\"85%\",\"Industry Benchmark\":\"80%\",\"Recommendation\":\"Maintain current strategies\"},{\"KPI\":\"Net Promoter Score\",\"Current Performance\":\"60\",\"Industry Benchmark\":\"70\",\"Recommendation\":\"Enhance customer loyalty programs\"},{\"KPI\":\"Delivery Efficiency\",\"Current Performance\":\"70%\",\"Industry Benchmark\":\"75%\",\"Recommendation\":\"Optimize supply chain processes\"},{\"KPI\":\"Pricing Competitiveness\",\"Current Performance\":\"65%\",\"Industry Benchmark\":\"70%\",\"Recommendation\":\"Conduct a comprehensive pricing analysis\"}]}]}}', '{}', NULL, NULL),
('600d7796-f511-48de-b222-7ae964155fbb', 'e7efe3cc-25ca-48af-9b45-4e83e3b9ec8e', 'c1af1646-895d-11f0-b862-da8ade92f675', 0, 'Nuovo Prompt', '', 'Sei un assistente esperto che analizza i dati dei questionari.', '[]', '2025-10-14 14:23:30', '2025-10-26 21:29:24', '{\"text\":[{\"id\":\"1\",\"title\":\"Introduzione\",\"shortcode\":\"intro\",\"prompt\":\"\"},{\"id\":\"2\",\"title\":\"Analisi Generale\",\"shortcode\":\"analisi_generale\",\"prompt\":\"\"}],\"charts\":[{\"id\":\"1\",\"title\":\"Panoramica Risultati\",\"shortcode\":\"chart_overview\",\"type\":\"bar\",\"prompt\":\"\"}],\"tables\":[{\"id\":\"1\",\"title\":\"Riepilogo Dati\",\"shortcode\":\"table_summary\",\"type\":\"simple\",\"prompt\":\"\"}]}', '', '{\"metadata\":{\"generated_at\":\"2025-10-26T17:29:24.474Z\",\"version\":\"1.0\"},\"prompt_structure\":{\"system_prompt\":\"Sei un assistente esperto che analizza i dati dei questionari.\",\"main_prompt\":\"\",\"sections_data\":{\"text\":[{\"id\":\"1\",\"title\":\"Introduzione\",\"shortcode\":\"intro\",\"prompt\":\"\"},{\"id\":\"2\",\"title\":\"Analisi Generale\",\"shortcode\":\"analisi_generale\",\"prompt\":\"\"}],\"charts\":[{\"id\":\"1\",\"title\":\"Panoramica Risultati\",\"shortcode\":\"chart_overview\",\"type\":\"bar\",\"prompt\":\"\"}],\"tables\":[{\"id\":\"1\",\"title\":\"Riepilogo Dati\",\"shortcode\":\"table_summary\",\"type\":\"simple\",\"prompt\":\"\"}]},\"reference_questionnaires\":{}},\"main_questionnaire\":{\"id\":\"c1af1646-895d-11f0-b862-da8ade92f675\",\"title\":\"Test Question\",\"description\":\"\",\"questions\":{\"title\":\"Test Question\",\"pages\":[{\"name\":\"page1\",\"elements\":[{\"type\":\"text\",\"name\":\"question1\"}]}],\"headerView\":\"advanced\"}},\"reference_questionnaires_data\":{},\"ai_generated_response\":{\"sections\":[{\"section_type\":\"text\",\"id\":\"1\",\"shortcode\":\"intro\",\"title\":\"Introduzione\",\"content\":\"Il presente report fornisce un\'analisi dettagliata dei dati raccolti attraverso i questionari somministrati. L\'obiettivo principale è quello di ottenere una comprensione approfondita delle opinioni e dei comportamenti dei partecipanti. I questionari sono stati progettati per coprire una gamma di argomenti, tra cui la soddisfazione generale, le preferenze e le aree di miglioramento. Attraverso l\'analisi dei dati, miriamo a identificare modelli e tendenze che possano guidare future decisioni strategiche. Questo documento è strutturato in sezioni che offrono un\'introduzione ai dati, un\'analisi dettagliata, e una panoramica visiva dei risultati. Le informazioni raccolte sono state processate con attenzione per garantire l\'accuratezza e la rilevanza delle conclusioni. Speriamo che questo report sia utile per capire meglio le esigenze e le aspettative dei partecipanti, e che fornisca spunti significativi per il miglioramento continuo.\"},{\"section_type\":\"text\",\"id\":\"2\",\"shortcode\":\"analisi_generale\",\"title\":\"Analisi Generale\",\"content\":\"L\'analisi generale dei questionari ha rivelato diversi insights chiave riguardanti le percezioni e le esperienze dei partecipanti. Una delle tendenze più evidenti è stata un alto livello di soddisfazione complessiva, con il 75% dei partecipanti che ha espresso un giudizio positivo. Le aree che hanno ricevuto il maggior numero di feedback positivi includono la qualità del servizio e la competenza del personale. Tuttavia, ci sono anche aree identificate per il miglioramento. Circa il 20% dei partecipanti ha indicato il desiderio di vedere miglioramenti nel tempo di risposta e nella disponibilità delle risorse. Inoltre, l\'analisi dei dati demografici ha mostrato che le preferenze possono variare significativamente tra diversi gruppi di età, suggerendo la necessità di adottare un approccio più personalizzato. Queste informazioni sono cruciali per sviluppare strategie mirate e migliorare ulteriormente l\'esperienza complessiva degli utenti.\"},{\"section_type\":\"chart\",\"id\":\"1\",\"shortcode\":\"chart_overview\",\"title\":\"Panoramica Risultati\",\"type\":\"bar\",\"data\":[{\"label\":\"Soddisfazione generale\",\"value\":75},{\"label\":\"Qualità del servizio\",\"value\":80},{\"label\":\"Competenza del personale\",\"value\":78},{\"label\":\"Tempo di risposta\",\"value\":65},{\"label\":\"Disponibilità risorse\",\"value\":58}]},{\"section_type\":\"table\",\"id\":\"1\",\"shortcode\":\"table_summary\",\"title\":\"Riepilogo Dati\",\"type\":\"simple\",\"headers\":[\"Aspetto\",\"Valore Medio\",\"Percentuale Positiva\",\"Aree di Miglioramento\"],\"rows\":[[\"Soddisfazione generale\",\"8/10\",\"75%\",\"Tempo di risposta\"],[\"Qualità del servizio\",\"8.2/10\",\"80%\",\"Varietà servizi\"],[\"Competenza del personale\",\"7.8/10\",\"78%\",\"Formazione\"],[\"Tempo di risposta\",\"6.5/10\",\"65%\",\"Efficienza\"],[\"Disponibilità risorse\",\"5.8/10\",\"58%\",\"Quantità\"]]}]}}', '{}', NULL, NULL),
('6b3744e0-0662-4920-85c9-e808a9554430', 'd094a9db-65ce-484f-83ad-b9f459973b93', '55031bf8-74b6-4e2b-b4cd-112a7628db6a', 0, 'Nuovo Prompt', '', 'Sei un assistente esperto che analizza i dati dei questionari.', '[]', '2026-02-28 08:46:47', '2026-02-28 08:46:47', '{\"text\":[{\"id\":\"1\",\"title\":\"Introduzione\",\"shortcode\":\"intro\",\"prompt\":\"\"},{\"id\":\"2\",\"title\":\"Analisi Generale\",\"shortcode\":\"analisi_generale\",\"prompt\":\"\"}],\"charts\":[{\"id\":\"1\",\"title\":\"Panoramica Risultati\",\"shortcode\":\"chart_overview\",\"type\":\"bar\",\"prompt\":\"\"}],\"tables\":[{\"id\":\"1\",\"title\":\"Riepilogo Dati\",\"shortcode\":\"table_summary\",\"type\":\"simple\",\"prompt\":\"\"}]}', '', '{\"metadata\":{\"generated_at\":\"2026-02-28T08:46:47.621Z\",\"version\":\"1.0\"},\"prompt_structure\":{\"system_prompt\":\"Sei un assistente esperto che analizza i dati dei questionari.\",\"main_prompt\":\"\",\"sections_data\":{\"text\":[{\"id\":\"1\",\"title\":\"Introduzione\",\"shortcode\":\"intro\",\"prompt\":\"\"},{\"id\":\"2\",\"title\":\"Analisi Generale\",\"shortcode\":\"analisi_generale\",\"prompt\":\"\"}],\"charts\":[{\"id\":\"1\",\"title\":\"Panoramica Risultati\",\"shortcode\":\"chart_overview\",\"type\":\"bar\",\"prompt\":\"\"}],\"tables\":[{\"id\":\"1\",\"title\":\"Riepilogo Dati\",\"shortcode\":\"table_summary\",\"type\":\"simple\",\"prompt\":\"\"}]},\"reference_questionnaires\":{}},\"main_questionnaire\":{\"id\":\"55031bf8-74b6-4e2b-b4cd-112a7628db6a\",\"title\":\"Murtaza form\",\"description\":\"\",\"questions\":{\"title\":\"Murtaza form\",\"pages\":[{\"name\":\"page1\",\"elements\":[{\"type\":\"radiogroup\",\"name\":\"question1\",\"title\":\"age\",\"choices\":[{\"value\":\"Item 1\",\"text\":\"123\"},{\"value\":\"Item 2\",\"text\":\"124\"},{\"value\":\"Item 3\",\"text\":\"156\"}]},{\"type\":\"file\",\"name\":\"question2\",\"title\":\"image\"}],\"title\":\"murtaza\"}],\"headerView\":\"advanced\"}},\"reference_questionnaires_data\":{},\"ai_generated