('q2b3c4d5-e6f7-5a8b-9c0d-1e2f3a4b5c6d', 'Marketing Strategy Assessment', 'Evaluate your current marketing approach', 'Be specific about your marketing activities and goals', '[{\"id\":\"m1\",\"type\":\"text\",\"question\":\"What is your target audience?\",\"required\":true},{\"id\":\"m2\",\"type\":\"checkbox\",\"question\":\"Which channels do you use?\",\"options\":[\"Social Media\",\"Email\",\"SEO\",\"Paid Ads\",\"Content Marketing\"],\"required\":true},{\"id\":\"m3\",\"type\":\"number\",\"question\":\"What is your monthly marketing budget (EUR)?\",\"required\":true}]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0),
('q3c4d5e6-f7a8-6b9c-0d1e-2f3a4b5c6d7e', 'Personal Development Plan', 'Discover your growth opportunities', 'Reflect on your current situation and aspirations', '[{\"id\":\"p1\",\"type\":\"text\",\"question\":\"What skills do you want to develop?\",\"required\":true},{\"id\":\"p2\",\"type\":\"textarea\",\"question\":\"What are your career goals for the next year?\",\"required\":true},{\"id\":\"p3\",\"type\":\"radio\",\"question\":\"How much time can you dedicate weekly?\",\"options\":[\"1-3 hours\",\"4-6 hours\",\"7-10 hours\",\"10+ hours\"],\"required\":true}]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0);

