INSERT INTO `reports` (`id`, `user_id`, `questionnaire_response_id`, `questionnaire_id`, `title`, `content`, `pdf_url`, `created_at`, `template_id`, `ai_response`) VALUES
('34b7657c-d158-4e5d-93cd-55fb2373e285', 'c465b6a4-d754-4c6a-aeca-7d14beaf4a64', 'd11d1325-b279-11f0-8e01-507b9dc7ff1a', 'c1af1646-895d-11f0-b862-da8ade92f675', 'Test Question', '{\"question1\":\"Testing\"}', '/uploads/pdfs/report_34b7657c-d158-4e5d-93cd-55fb2373e285_1761489681476.pdf', '2025-10-26 18:41:21', NULL, '{\"sections\":[{\"section_type\":\"text\",\"id\":\"1\",\"shortcode\":\"intro\",\"title\":\"Introduzione\",\"content\":\"Il presente report si propone di analizzare i dati derivanti dai questionari raccolti, con l\'obiettivo di fornire un quadro esaustivo delle informazioni ottenute e delle implicazioni che queste comportano per le decisioni strategiche future. I dati raccolti attraverso il primo quesito del questionario, denominato \'Testing\', offrono un\'interessante prospettiva sull\'efficacia dei metodi attuali e permettono di individuare opportunità di miglioramento. Attraverso un\'analisi dettagliata, esploreremo i punti di forza emersi e le aree critiche che necessitano di ulteriori interventi. Sarà fondamentale comprendere come i risultati ottenuti possano influenzare le pratiche operative e come possano essere utilizzati per ottimizzare i processi. Il report si articolerà in diverse sezioni, ciascuna dedicata a un aspetto specifico dell\'analisi, garantendo un\'approfondita comprensione dei dati e delle loro implicazioni pratiche.\"},{\"section_type\":\"text\",\"id\":\"2\",\"shortcode\":\"analisi_generale\",\"title\":\"Analisi Generale\",\"content\":\"L\'analisi generale dei dati raccolti attraverso la domanda \'Testing\' evidenzia una serie di risultati chiave che meritano attenzione. In primo luogo, il livello complessivo di soddisfazione degli intervistati risulta essere elevato, indicando una percezione positiva delle attuali pratiche in uso. Tuttavia, è emerso anche un bisogno di miglioramento in aree specifiche, come l\'implementazione di nuove tecnologie e la formazione continua del personale. I dati rivelano inoltre una correlazione tra la percezione della qualità e l\'efficienza operativa, suggerendo che investimenti in queste aree potrebbero portare a miglioramenti tangibili. È fondamentale che le organizzazioni utilizzino questi insight per sviluppare strategie mirate, che possano non solo rispondere ai bisogni immediati ma anche preparare il terreno per il successo a lungo termine.\"},{\"section_type\":\"chart\",\"id\":\"1\",\"shortcode\":\"chart_overview\",\"title\":\"Panoramica Risultati\",\"type\":\"bar\",\"data\":{\"labels\":[\"Q1 2024\",\"Q2 2024\",\"Q3 2024\",\"Q4 2024\"],\"values\":[78,85,90,93]}},{\"section_type\":\"table\",\"id\":\"1\",\"shortcode\":\"table_summary\",\"title\":\"Riepilogo Dati\",\"headers\":[\"Parametro\",\"Valore\",\"Stato\",\"Note\"],\"rows\":[[\"Soddisfazione\",\"85%\",\"Buono\",\"In linea con le aspettative\"],[\"Qualità\",\"90%\",\"Ottimo\",\"Risultato positivo\"],[\"Efficienza\",\"93%\",\"Eccellente\",\"Supera gli obiettivi\"],[\"Innovazione\",\"78%\",\"Adeguato\",\"Necessita di miglioramenti\"]]}]}'),
('40a1e60e-cd1d-4389-801b-269c8ec1b55f', 'd2ba9956-518c-4ec5-83af-8293aa410ff5', '197a9675-a9b3-11f0-bd28-507b9dc7ff1a', 'c1af1646-895d-11f0-b862-da8ade92f675', 'Test Question', '{\"question1\":\"asdsad\"}', '/uploads/pdfs/report_40a1e60e-cd1d-4389-801b-269c8ec1b55f_1760524725996.pdf', '2025-10-15 13:38:45', NULL, '{\"sections\":[{\"section_type\":\"text\",\"id\":\"1\",\"shortcode\":\"intro\",\"title\":\"Introduzione\",\"content\":\"Il presente report analizza i dati provenienti dai questionari raccolti. L\'obiettivo principale è comprendere le tendenze generali e i modelli emergenti dai dati forniti. Inizialmente, la nostra attenzione si concentra su una panoramica delle risposte ricevute, esplorando in dettaglio le implicazioni e le intuizioni che ne derivano. L\'analisi dei dati quantitativi e qualitativi ci consente di identificare le aree di miglioramento e quelle di successo. È essenziale considerare questi risultati nel contesto più ampio delle dinamiche aziendali e del mercato attuale. Questo approccio ci permette di formulare strategie informate per migliorare le performance complessive e soddisfare le esigenze degli stakeholder.\"},{\"section_type\":\"text\",\"id\":\"2\",\"shortcode\":\"analisi_generale\",\"title\":\"Analisi Generale\",\"content\":\"L\'analisi generale dei dati del questionario rivela diverse tendenze significative. La risposta \'asdsad\', sebbene possa sembrare irrilevante, evidenzia la necessità di una maggiore chiarezza nelle domande poste. È fondamentale che le domande siano formulate in modo da ottenere risposte utili e pertinenti. I dati indicano che è possibile migliorare l\'efficacia dei questionari attraverso una progettazione più attenta, assicurando che le domande siano mirate e che i partecipanti comprendano chiaramente cosa viene chiesto. L\'analisi suggerisce anche che l\'interpretazione delle risposte deve essere contestualizzata, tenendo conto delle variabili esterne che potrebbero influenzare i risultati. Questo approccio integrato garantisce una migliore comprensione delle risposte e una maggiore utilità pratica dei risultati del questionario.\"},{\"section_type\":\"chart\",\"id\":\"1\",\"shortcode\":\"chart_overview\",\"title\":\"Panoramica Risultati\",\"type\":\"bar\",\"data\":{\"labels\":[\"Gennaio\",\"Febbraio\",\"Marzo\",\"Aprile\"],\"values\":[70,65,80,75]}},{\"section_type\":\"table\",\"id\":\"1\",\"shortcode\":\"table_summary\",\"title\":\"Riepilogo Dati\",\"headers\":[\"Categoria\",\"Valore\",\"Stato\",\"Note\"],\"rows\":[[\"Risposta\",\"asdsad\",\"Irrelevante\",\"Richiede revisione\"],[\"Completezza\",\"75%\",\"Parziale\",\"Da migliorare\"],[\"Chiarezza\",\"65%\",\"Moderato\",\"Necessita di chiarimenti\"],[\"Pertinenza\",\"60%\",\"Basso\",\"Richiede maggiore attenzione\"]]}]}'),
('9c470788-2750-42dd-b4c0-c1d9e195846a', 'd2ba9956-518c-4ec5-83af-8293aa410ff5', '9da2fb06-a854-11f0-b84a-507b9dc7ff1a', '6d095e06-9321-11f0-b862-da8ade92f675', 'Test AFG', '{\"question1\":\"Ali Haider\",\"question2\":[\"Item 1\"]}', '/uploads/pdfs/report_9c470788-2750-42dd-b4c0-c1d9e195846a_1760374197010.pdf', '2025-10-13 19:49:56', NULL, '{\"sections\":[{\"section_type\":\"text\",\"id\":\"1\",\"shortcode\":\"intro\",\"title\":\"Introduzione\",\"content\":\"Il nome \'Ali Haider\' ha un significato profondo e storico. \'Ali\' è un nome di origine araba che significa \'elevato\' o \'nobile\'. È un nome comune nelle culture islamiche, spesso associato a Ali ibn Abi Talib, un importante figura storica e religiosa. \'Haider\', d\'altra parte, significa \'leone\' ed è un epiteto di Ali ibn Abi Talib, noto per il suo coraggio e la sua forza. L\'unione di \'Ali\' e \'Haider\' evoca una personalità caratterizzata da nobiltà, forza e coraggio. Le persone con questo nome sono spesso viste come leader naturali, con un forte senso di giustizia e determinazione. Sono capaci di affrontare le sfide con determinazione e grazia, guadagnandosi il rispetto di chi li circonda.\"},{\"section_type\":\"text\",\"id\":\"2\",\"shortcode\":\"analisi_generale\",\"title\":\"Analisi Generale\",\"content\":\"L\'analisi del nome \'Ali Haider\' rivela una combinazione di qualità che sono spesso associate alla leadership e al coraggio. La personalità di chi porta questo nome tende a essere influente, guidata da un forte senso di responsabilità e integrità. La parte \'Ali\' del nome implica una predisposizione naturale verso l\'elevazione personale e professionale, suggerendo una ricerca continua di miglioramento e riconoscimento. \'Haider\', invece, aggiunge un elemento di forza e resilienza, indicando una capacità innata di affrontare le avversità con tenacia. Queste caratteristiche rendono \'Ali Haider\' non solo un nome significativo, ma anche un riflesso di qualità che possono ispirare fiducia e rispetto in ambito sociale e professionale. Chi porta questo nome potrebbe eccellere in ruoli che richiedono decisioni rapide e leadership strategica.\"},{\"section_type\":\"chart\",\"id\":\"1\",\"shortcode\":\"chart_overview\",\"title\":\"Panoramica Risultati\",\"type\":\"bar\",\"data\":{\"labels\":[\"Gennaio\",\"Febbraio\",\"Marzo\",\"Aprile\",\"Maggio\"],\"values\":[75,80,85,90,95]}},{\"section_type\":\"table\",\"id\":\"1\",\"shortcode\":\"table_summary\",\"title\":\"Riepilogo Dati\",\"headers\":[\"Metrica\",\"Valore\",\"Stato\",\"Note\"],\"rows\":[[\"Progresso\",\"85%\",\"Buono\",\"In miglioramento\"],[\"Qualità\",\"90%\",\"Eccellente\",\"Sopra la media\"],[\"Efficienza\",\"88%\",\"Buono\",\"In linea con gli obiettivi\"],[\"Innovazione\",\"92%\",\"Eccellente\",\"Innovativo\"],[\"Soddisfazione\",\"87%\",\"Buono\",\"Feedback positivo\"]]}]}');

